function Nav() {
  const [scrolled, setScrolled] = useState(false);
  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  const menu = ['학원소개', '시스템', '실적', '후기', '블로그', '상담신청'];

  return (
    <nav
      className="fixed top-0 left-0 right-0 z-50 transition-all duration-300"
      style={{
        background: scrolled ? 'rgba(250,247,241,0.95)' : 'rgba(250,247,241,0.4)',
        backdropFilter: 'blur(12px)',
        borderBottom: scrolled ? `1px solid ${COLORS.line}` : '1px solid transparent',
      }}
    >
      <div className="max-w-7xl mx-auto px-6 sm:px-10 py-4 flex items-center justify-between">
        <a href="#" className="flex items-center">
          <img
            src={LOGO_HORIZONTAL}
            alt="오르라수학전문학원"
            style={{ height: 40, width: 'auto', display: 'block' }}
          />
        </a>

        <ul className="hidden lg:flex items-center gap-8" style={{ fontSize: 14 }}>
          {menu.map((m) => (
            <li key={m}>
              <a
                href={`#${m}`}
                className="transition-colors hover:opacity-60"
                style={{ color: COLORS.ink, letterSpacing: '0.02em' }}
              >
                {m}
              </a>
            </li>
          ))}
        </ul>

        <a
          href="tel:053-290-3821"
          className="px-4 py-2 text-sm transition-all hover:opacity-90"
          style={{
            background: COLORS.crimson,
            color: COLORS.cream,
            letterSpacing: '0.04em',
          }}
        >
          053-290-3821
        </a>
      </div>
    </nav>
  );
}

